                    eprintln!("  stderr:\n{}", r.stderr);
                }
                Err(e) => {
                    failures += 1;
                    eprintln!("not ok - {step_name} :: {test_name} ({e})");
                }
            }
        }
        if failures > 0 {
            eyre::bail!("{failures} test(s) failed");
        }
        Ok(())
